-- ── Pinepods ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pinepods is a free, open-source, self-hosted podcast management system, built in Rust, that lets users run their own podcast server and sync subscriptions, playback history and downloads across web, desktop and mobile clients.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (open-source community project)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (open-source project with no corporate headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Pinepods Review 2026: Features, Setup and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pinepods review: features, self-hosting setup, pricing (free/open source) and alternatives like AntennaPod for self-hosted podcast management.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pinepods, also written PinePods, is a free and open-source, self-hosted podcast management system created by developer Collin Pendleton, known on GitHub as madeofpendletonwool, and released under the GNU General Public License v3.0 (GPL-3.0). It is written primarily in Rust and is designed around a single self-hosted server, backed by PostgreSQL or MySQL/MariaDB, that a household or team can run on their own hardware, with every device including web, desktop apps for Windows, Mac and Linux, Android, iOS, and a command-line client called Firewood syncing to that one server so subscriptions, playback history, download queue and settings follow the user across devices. Its core differentiator versus mainstream commercial podcast apps like Spotify, Apple Podcasts or Pocket Casts is data ownership and self-hosting: because everything lives in the user's own database rather than a vendor's cloud, there is no subscription fee, no advertising, and no dependency on a third-party company staying in business. Pinepods also supports multiple user accounts on a single server instance, so a household can share one deployment while keeping separate libraries, statistics and settings, and it exposes a built-in gpodder-compatible sync server so it can interoperate with other open-source podcast clients such as AntennaPod. Additional features include search across the Podcast Index, iTunes and YouTube catalogs plus in-library search, OIDC and SSO support with multi-factor authentication via TOTP for self-hosted security, OPML import and export for migrating subscriptions from other apps, push notifications via ntfy or webhooks, multiple UI themes with a custom theme creator, and community translations into 36 languages. As with any self-hosted software, it is entirely free to use, with the only cost being the server infrastructure the user chooses to run it on, commonly Docker Compose paired with PostgreSQL. Pinepods targets privacy-conscious podcast listeners, homelab and self-hosting enthusiasts, and small teams or families who want a shared podcast library without depending on a commercial streaming platform. Its closest competitors are other open-source, self-hosted podcast tools such as AntennaPod, an Android-only client, and Podgrab and Podfetch, which are download-focused podcast archivers, as well as commercial alternatives like Pocket Casts and Overcast that offer hosted convenience but not self-hosting or data ownership.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '85c3b235-223c-45ae-bc99-db8243a2c741';

