-- ── Pingboard ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pingboard, now sold as Workleap Pingboard, is an org chart and employee directory platform that helps HR and people teams visualize company structure, onboard new hires and keep employee information up to date.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$4/user/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (part of Workleap)$q$, company_size),
  headquarters = COALESCE($q$Montreal, Quebec, Canada (Workleap headquarters); Pingboard was originally based in Texas, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Pingboard Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pingboard (Workleap Pingboard) review: org chart and employee directory features, pricing, pros and cons, and alternatives like ChartHop in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pingboard is org chart and employee directory software originally built by an HR tech company founded in 2013 and based in Texas, that helps HR and people operations teams create dynamic, always-up-to-date visualizations of company reporting structures, searchable employee directories, and onboarding workflows for new hires. In December 2023, Pingboard was acquired by Workleap, a Montreal, Canada-based employee experience software company, and the product is now marketed and sold as Workleap Pingboard alongside Workleap's other HR and people-management tools, reflecting a broader industry trend of employee-experience platforms consolidating point solutions like org charts into unified suites. Pingboard's core differentiator is that its org charts update automatically as employee data changes, rather than requiring manual redrawing in tools like PowerPoint, Visio or Lucidchart, and it combines that with a searchable people directory, team and skills directories, and onboarding checklists so new hires can quickly learn who is who and how the company is structured. Pricing is subscription-based and priced per user per month, starting at around 4 dollars per user per month on annual billing, or roughly 5 dollars per user per month if billed monthly; Workleap uses a modular pricing approach where customers can add Pingboard alongside other Workleap products, and organizations above roughly 250 employees are directed to contact sales for custom enterprise pricing. Pingboard targets HR, people operations and internal communications teams at small and mid-sized businesses that want a lightweight, purpose-built org chart and directory tool rather than building this functionality manually or bolting it onto a full HRIS. Its competitors include dedicated org chart tools like ChartHop, directory and onboarding features bundled into broader HRIS platforms such as BambooHR and Rippling, and general diagramming tools like Lucidchart and Microsoft Visio that some smaller companies use as a manual substitute for a dedicated org chart product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3e8b9691-f4ea-48a6-bf97-0daae2c823ac';

