-- ── Pinpoint ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pinpoint (pinpointhq.com) is an applicant tracking system and recruitment marketing platform that helps in-house talent acquisition teams manage job postings, candidate pipelines, interview scheduling and employer branding.$q$, short_description),
  pricing_model = COALESCE($q$Custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom (contact sales)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Pinpoint ATS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pinpoint (pinpointhq.com) ATS review: career sites, hiring pipeline features, custom pricing, pros and cons, and alternatives like Greenhouse in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pinpoint, operating at pinpointhq.com, is an applicant tracking system (ATS) and recruitment software platform founded in 2017 and headquartered in the United Kingdom, built specifically for in-house talent acquisition teams rather than external recruitment agencies. It should not be confused with Amazon Web Services' Pinpoint, which is a customer engagement and messaging service, or with Atlassian's product of the same name; this Pinpoint is purely a hiring and recruitment platform. The company positions itself around three integrated pillars: attracting candidates through a drag-and-drop career site builder with SEO optimization and no-code editing, managing the hiring process through a full ATS with pipeline management, structured interview scorecards, collaborative candidate evaluation and offer management, and automating repetitive recruiting admin work such as interview scheduling, candidate communication sequences and reporting. Its key differentiator versus larger US-centric competitors like Greenhouse and Lever is a stronger built-in focus on employer branding and candidate experience out of the box rather than requiring separate marketing tools, GDPR-native data handling that appeals to UK and EU-based companies, and typically faster implementation timelines, commonly cited around two to four weeks versus longer enterprise rollouts. Pinpoint uses custom, quote-based pricing rather than publicly listed plans; prospective customers request pricing tailored to hiring volume, team size and feature needs via the company's sales team, and third-party pricing guides estimate costs ranging from several hundred to a few thousand dollars per month depending on company size, though Pinpoint does not publish these figures itself. The platform primarily targets mid-market and larger in-house talent acquisition teams, commonly organizations in roughly the 200 to 2,000 employee range, across industries including technology, healthcare, retail and professional services, who need a single system to manage employer branding, applications and hiring workflow rather than assembling separate tools for each. Pinpoint's main competitors in the ATS market include Greenhouse and Lever, both larger US-based platforms with deeper enterprise integration ecosystems, as well as Workable and JazzHR, which target smaller and mid-sized businesses respectively; Pinpoint is generally positioned between these as a mid-market-focused, UK and EU-friendly alternative.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1850649f-0915-4e09-87b7-b7aa588ddd00';

