INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$What is Piktochart used for?$q$, $q$It is used to create infographics, presentations, reports and social media graphics without needing design software skills.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Is Piktochart free?$q$, $q$Yes, there is a free plan, though it limits downloads and AI credits; paid plans start around $10/month billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Does Piktochart have AI features?$q$, $q$Yes, it includes an AI generator that produces first-draft designs or copy from a text prompt, using a monthly AI credit allowance.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Who owns Piktochart?$q$, $q$Piktochart is a privately held, bootstrapped company founded in 2011 and headquartered in Malaysia.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$What is the difference between Piktochart and Canva?$q$, $q$Piktochart specializes in data-driven infographics and reports, while Canva is a broader general-purpose design platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Can teams collaborate in Piktochart?$q$, $q$Yes, collaboration features are available on Business and higher plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Does Piktochart offer education pricing?$q$, $q$Yes, discounted Education and Nonprofit plans are available.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$What file formats can I export from Piktochart?$q$, $q$PNG on the free plan, with PDF, PPT and GIF export unlocked on paid plans.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Marketing reports and infographics$q$, $q$Marketing teams turn campaign data into shareable infographics and reports.$q$, $q$Marketers and content teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Classroom and educational materials$q$, $q$Teachers and students build visual lesson materials and presentations.$q$, $q$Educators and students$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Internal communications$q$, $q$HR and internal comms teams create org updates, newsletters and social graphics.$q$, $q$HR and internal communications teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Unlimited projects","2 PNG downloads","60 AI credits","1GB storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Pro$q$, $q$$10/month billed annually ($15/month billed monthly)$q$, $q$annual or monthly$q$, NULL, $q$["Unlimited PNG downloads","500 AI credits","Premium templates","100GB storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Business$q$, $q$$17/month billed annually ($20/month billed monthly)$q$, $q$annual or monthly$q$, NULL, $q$["Everything in Pro","Unlimited PDF and PPT downloads","Unlimited Brand Kit","1,000 AI credits","250GB storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["SSO/SAML","Dedicated account manager","Custom templates","Security review"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Piktochart is a browser-based design tool built around the idea that anyone, not just trained designers, should be able to turn data and ideas into clear visual content. Rather than starting from a blank canvas, users pick from hundreds of templates for infographics, reports, presentations, resumes and social graphics, then customize colors, text, icons and charts with a drag-and-drop editor.$q$, $q$Founded in 2011 in Malaysia, Piktochart has grown into an established, bootstrapped SaaS company serving marketers, educators, HR teams and small businesses worldwide. It has increasingly layered AI-assisted generation on top of its template system, letting users produce a first-draft design or copy from a short text prompt before refining it manually.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Piktochart's strongest feature set centers on data visualization: users can paste in or upload spreadsheet data and have it automatically rendered as charts, maps or infographic elements, which makes it popular for reports and internal communications where numbers need to be explained visually rather than in a table.$q$, $q$Beyond charts, the platform includes a Brand Kit for locking in company colors, fonts and logos, a library of millions of icons, illustrations and stock photos, and export options ranging from static PNGs on the free plan to PDF, PowerPoint and animated GIF or video exports on paid plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5db9612-39d7-4c31-8562-b26cbfaca743', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Piktochart uses a freemium model. The Free plan is generous on project creation but limited on downloads (two PNG exports) and AI credits, making it best for occasional or evaluation use. The Pro plan removes the PNG download cap and increases AI credits and storage, while Business adds unlimited PDF and PPT exports plus an unlimited Brand Kit for teams that need brand consistency across many pieces of content.$q$, $q$Larger organizations can move to a custom-priced Enterprise plan that adds SSO/SAML, a dedicated account manager and security reviews, and Piktochart also offers discounted Education and Nonprofit plans as well as a Campus license for institutions with 3,000 or more seats.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Unified PIM/MDM$q$, $q$Centralize product and master data across channels in one data model.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Digital Asset Management$q$, $q$Store, tag and distribute images, video and documents with automated workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Headless/hybrid CMS$q$, $q$Deliver content to web, mobile and other channels via APIs or traditional templating.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Multi-language and multi-store support$q$, $q$Manage localized product content and storefronts from one system.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Workflow and versioning$q$, $q$Enterprise editions add approval workflows and object versioning at scale.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Digital commerce framework$q$, $q$Extend product data into transactional commerce experiences.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Open architecture$q$, $q$Built on PHP and Symfony with a React/TypeScript admin interface and REST/GraphQL APIs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Flexible deployment$q$, $q$Run self-hosted on your own infrastructure or through Pimcore's hosting partners.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Combines PIM, DAM, MDM and CMS in one platform, reducing tool sprawl$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Free, self-hostable Community Edition with no per-seat licensing$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Highly extensible via a large plugin and bundle ecosystem plus open APIs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Strong fit for complex, multi-language, multi-channel product catalogs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Backed by a company with enterprise support and a partner/integrator network$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$2025 licensing shift to a proprietary model for parts of v12 has created community uncertainty$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Steep learning curve and typically requires developer or integrator involvement to implement$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Community Edition lacks enterprise workflow and support features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Enterprise and Professional pricing is not publicly listed and requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Smaller ecosystem and mindshare than pure-play PIM leaders like Akeneo in some markets$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Is Pimcore free?$q$, $q$The Community Edition is free and self-hosted; Professional and Enterprise editions are custom priced.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Is Pimcore still open source?$q$, $q$It was historically fully open source; as of version 12 in 2025, parts of the platform moved to a proprietary Pimcore Open Core License, prompting a community fork called OpenDXP.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$What does PIM stand for in Pimcore?$q$, $q$Product Information Management, one of the core modules alongside DAM, MDM and CMS.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Who founded Pimcore?$q$, $q$Pimcore GmbH was founded in 2013 by Dietmar Rietsch, building on a project first released in 2010.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$What is Pimcore used for?$q$, $q$Managing product data, digital assets, master data and content across web and commerce channels.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$What technology is Pimcore built on?$q$, $q$PHP and the Symfony framework, with MySQL/MariaDB storage and a React/TypeScript admin interface.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$How does Pimcore compare to Akeneo?$q$, $q$Pimcore bundles PIM with DAM, CMS and commerce tooling, while Akeneo is a more specialized, PIM-focused product.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Does Pimcore offer cloud hosting?$q$, $q$Yes, managed hosting options exist alongside self-hosted deployment.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Retail and e-commerce product catalogs$q$, $q$Retailers and D2C brands centralize product data and push it across web and marketplace channels.$q$, $q$Retailers and e-commerce brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Manufacturing and B2B data consolidation$q$, $q$Manufacturers and distributors unify complex technical product data and master data.$q$, $q$Manufacturers and distributors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Custom digital experience implementations$q$, $q$Agencies and system integrators build tailored PIM/DAM/CMS solutions on the open platform.$q$, $q$Digital agencies and system integrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Community Edition$q$, $q$Free$q$, $q$self-hosted, no subscription$q$, NULL, $q$["Core PIM, MDM, DAM and CMS functionality","Open-core codebase","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$Enterprise Edition$q$, $q$Custom (contact sales)$q$, $q$annual license$q$, NULL, $q$["Advanced workflow management","Enterprise-grade versioning","Dedicated support and SLA"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pimcore began life in 2010 as an internal project at a digital agency before becoming a standalone company, Pimcore GmbH, in 2013 in Salzburg, Austria. Rather than building a single-purpose product, the team combined product information management, digital asset management, master data management and content management into one open-core platform, aiming to reduce the number of disconnected systems that enterprises typically need for product and content data.$q$, $q$The platform is used mainly by mid-market and enterprise organizations, particularly retailers and manufacturers, that manage large product catalogs across many languages, brands and sales channels, as well as by system integrators who build custom implementations for clients on top of the core framework.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Pimcore lets teams model structured product and master data, manage digital assets such as images and video with tagging and automated workflows, and deliver content across web, mobile and other channels through a headless or hybrid CMS with REST and GraphQL APIs. Multi-language and multi-store support is a particular strength, letting one system drive localized product content across regions.$q$, $q$The Enterprise and Professional editions add capabilities aimed at large organizations, including approval workflows, object versioning at scale, and dedicated support, while the platform's open architecture and bundle ecosystem let developers extend functionality well beyond the out-of-the-box feature set.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pimcore's Community Edition remains free to download and self-host, which makes it accessible to smaller teams and developers who are comfortable managing their own infrastructure. It is important to note that Pimcore introduced a proprietary license, the Pimcore Open Core License, for parts of version 12 in 2025, a departure from its fully open-source history that led some community members to fork the project as OpenDXP.$q$, $q$Professional and Enterprise editions are priced on a custom, quote-based basis tied to factors like data volume, number of users and required support level, so organizations evaluating Pimcore for production use should expect to contact sales for a proposal rather than finding fixed public pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('392c0dc0-952f-4089-9489-2c63d22bd5a1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Managed vector indexing$q$, $q$Fully hosted approximate nearest-neighbor search with no infrastructure to manage.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Dense, sparse and full-text indexes$q$, $q$Combine semantic and keyword-style search in one platform.$q$, 1);
