INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Multi-cloud availability$q$, $q$Deploy across AWS, Azure and GCP regions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Bring Your Own Cloud (BYOC)$q$, $q$Run Pinecone inside a customer's own cloud account for data residency.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Fully managed, minimal operational overhead$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Scales to large vector volumes with predictable performance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Combines dense, sparse and full-text search in one service$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Built-in embedding and reranking simplify RAG pipelines$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Enterprise security features such as SSO, RBAC and audit logs on higher tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Costs can grow quickly at scale compared with self-hosted open-source options$q$, 0);
