INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Free Starter tier has restrictive limits on indexes and namespaces$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Standard and Enterprise plans carry monthly usage minimums$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Less control over underlying infrastructure than open-source alternatives like Milvus or Weaviate$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$What is Pinecone used for?$q$, $q$Storing and querying vector embeddings to power semantic search, recommendations and retrieval-augmented generation (RAG).$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Is Pinecone free?$q$, $q$Yes, the Starter plan is free with usage limits; paid plans start with a flat $20/month Builder tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Who founded Pinecone?$q$, $q$Edo Liberty, a former head of Amazon AI Labs, founded Pinecone in 2019.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Is Pinecone open source?$q$, $q$No, it is a proprietary managed service, unlike open-source alternatives such as Milvus or Weaviate.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$What is RAG and how does Pinecone help?$q$, $q$Retrieval-augmented generation retrieves relevant context for an LLM; Pinecone stores and retrieves that context as vector embeddings.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Does Pinecone support hybrid search?$q$, $q$Yes, it supports dense, sparse and full-text indexes that can be combined for hybrid search.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Can Pinecone run in my own cloud account?$q$, $q$Yes, via the Bring Your Own Cloud (BYOC) option, priced on a custom basis.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$How is Pinecone priced?$q$, $q$Usage-based pricing across Starter (free), Builder, Standard and Enterprise tiers, plus custom BYOC pricing.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$RAG applications for LLM assistants$q$, $q$AI teams retrieve relevant context from a Pinecone index to ground LLM responses in accurate data.$q$, $q$AI and ML engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Semantic search for content and product catalogs$q$, $q$Search and product teams power natural-language search over large content or product catalogs.$q$, $q$Search and product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Recommendation engines$q$, $q$Data science teams use embedding similarity to power personalized recommendations.$q$, $q$Data science teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Starter$q$, $q$Free$q$, $q$monthly$q$, NULL, $q$["Up to 5 indexes","100 namespaces per index","2GB storage","2M write / 1M read units monthly","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Builder$q$, $q$$20/month flat$q$, $q$monthly$q$, NULL, $q$["10 indexes per project","1,000 namespaces per index","10GB storage","Monitoring integrations","Up to 5 projects and users"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Standard$q$, $q$$50/month minimum, pay-as-you-go$q$, $q$monthly$q$, NULL, $q$["Unlimited indexes (up to 20/project)","Dedicated read nodes","Backup and restore","SSO","All cloud regions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$Enterprise$q$, $q$$500/month minimum, pay-as-you-go$q$, $q$monthly$q$, NULL, $q$["99.95% uptime SLA","Private networking","Audit logs","HIPAA compliance","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pinecone was founded in 2019 by Edo Liberty, a former head of Amazon AI Labs, to solve a problem that became central to the generative AI boom: how to store and quickly search massive numbers of vector embeddings produced by machine learning models. The company is headquartered in New York with additional presence in San Francisco and has raised roughly 138 million dollars in venture funding, most recently at a valuation of around 750 million dollars.$q$, $q$As a fully managed service, Pinecone removes the operational burden of running vector search infrastructure yourself, which has made it a popular default choice for teams building retrieval-augmented generation (RAG) pipelines, semantic search and recommendation systems on top of large language models.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pinecone supports dense vector search for semantic similarity, sparse indexes for keyword-style matching, and full-text search, letting teams combine these approaches for hybrid search inside a single service. It also includes built-in embedding generation and reranking, reducing the number of separate tools needed to build a RAG pipeline.$q$, $q$Higher tiers add production-grade features such as dedicated read nodes for predictable performance, backup and restore, role-based access control, SAML SSO, and a Bring Your Own Cloud option that lets regulated organizations run Pinecone inside their own cloud account.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d37dae4-b21a-4385-9295-c71506f8ef9c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pinecone prices usage-based across four main tiers. Starter is free with capped indexes, namespaces and monthly read/write units, suitable for prototypes and small projects. Builder adds a flat 20 dollar per month fee for higher limits and light team usage.$q$, $q$Standard and Enterprise plans are pay-as-you-go with monthly minimums of 50 and 500 dollars respectively, scaling up to unlimited indexes, dedicated infrastructure, private networking and compliance features like HIPAA support and audit logs for regulated industries.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Visual HTML/CSS editing$q$, $q$Edit real project files visually with live two-way sync to code.$q$, 0);
