INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Less suited to non-technical users than Webflow or Squarespace$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Is Pinegrow a website builder or a code editor?$q$, $q$Both; it is a visual editor that works directly on real HTML/CSS project files rather than a hosted CMS.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Does Pinegrow require a subscription?$q$, $q$No, one-time license purchases are available alongside annual and monthly subscriptions.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Does Pinegrow support WordPress?$q$, $q$Yes, via the separately priced WordPress Builder add-on.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Does Pinegrow host my website?$q$, $q$No, Pinegrow exports standard code that you host anywhere you choose.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$What frameworks does Pinegrow support?$q$, $q$Bootstrap, Foundation and Tailwind CSS are all supported through framework-aware smart components.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Is Pinegrow available for Mac and Linux?$q$, $q$Yes, it runs natively on Mac, Windows and Linux.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Who makes Pinegrow?$q$, $q$Pinegrow Pte. Ltd., a small Singapore-based company founded by Matjaz Trontelj.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Can teams use Pinegrow together?$q$, $q$Yes, team and multi-seat licensing options are available.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Freelance client website builds$q$, $q$Freelance developers build client websites visually while retaining full code control.$q$, $q$Freelance web developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$WordPress theme development$q$, $q$Agencies build and customize WordPress themes visually instead of hand-coding everything.$q$, $q$WordPress agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Framework prototyping$q$, $q$Front-end developers prototype Tailwind CSS or Bootstrap layouts quickly before handing off code.$q$, $q$Front-end developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Web Editor (annual subscription)$q$, $q$$99/year (promotional pricing may apply)$q$, $q$annual$q$, NULL, $q$["Full visual HTML/CSS editor","Pinegrow Online for local projects","Framework-aware components"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Web Editor (monthly subscription)$q$, $q$from $12/month$q$, $q$monthly$q$, NULL, $q$["Same core editor features","Cancel anytime"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$One-time license$q$, $q$Custom per edition (historically $93 to $139)$q$, $q$one-time$q$, NULL, $q$["Perpetual use of the current version","1 year of free updates included","Renewable updates at reduced price"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$Add-ons (Interactions, Tailwind Editor, WordPress Builder, Shop Builder)$q$, $q$$25 to $50/year or one-time, per add-on$q$, $q$annual or one-time$q$, NULL, $q$["Extend core editor with framework- or CMS-specific tools"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pinegrow is a desktop application, not a hosted website builder, that opens and edits your own HTML, CSS and SASS project files directly on your computer. It is published by Pinegrow Pte. Ltd., a small Singapore-based company founded by Matjaz Trontelj, and has built a loyal following among developers who want visual editing speed without losing control over the underlying code.$q$, $q$The tool is designed for professionals working with real front-end code and popular frameworks, rather than beginners looking for a fully hosted, no-code solution, which sets it apart from mainstream builders like Wix or Squarespace.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pinegrow's editor supports live, multi-page editing where changes to shared headers, footers or components update across an entire site at once, along with a visual CSS Grid and Flexbox editor for building responsive layouts without hand-writing every rule. Smart components understand the conventions of Bootstrap, Foundation and Tailwind CSS so visual changes stay compatible with those frameworks.$q$, $q$Paid add-ons extend the core editor for specific workflows: a WordPress Builder for creating themes and plugins visually, an Interactions add-on for scroll and click-triggered animations without JavaScript, a Tailwind CSS visual editor, and a Shop Builder for WooCommerce stores.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pinegrow offers both subscription and one-time license options, which is unusual among modern design tools. The annual subscription for the core Web Editor is priced around 99 dollars per year, with a monthly option also available, while a one-time perpetual license lets users keep using the current version forever after a single payment, with one year of free updates included and renewable updates afterward at a reduced price.$q$, $q$Each add-on, such as Interactions, the Tailwind Visual Editor, WordPress Builder or Shop Builder, is priced separately, typically in the 25 to 50 dollar per year range or as a comparable one-time purchase, letting customers pay only for the specific workflows they need.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cce62d49-de89-4c74-80bb-713e85f97dbe', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Self-hosted podcast server$q$, $q$Run your own server; nothing depends on a third-party cloud service.$q$, 0);
