INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$gpodder-compatible sync$q$, $q$Interoperate with other open-source clients like AntennaPod.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Multi-source search$q$, $q$Search Podcast Index, iTunes and YouTube plus your own library.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$OIDC/SSO and MFA$q$, $q$Secure self-hosted deployments with single sign-on and TOTP-based multi-factor authentication.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$OPML import/export$q$, $q$Migrate subscriptions in or out of Pinepods easily.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Custom themes$q$, $q$Multiple built-in themes plus a custom theme creator.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Completely free and open source under GPL-3.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Full data ownership; no vendor lock-in or ad-supported model$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Supports multiple users on one self-hosted instance$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Broad platform coverage including CarPlay and Android Auto support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Actively translated into many languages by the community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Requires self-hosting knowledge such as Docker and database setup, unlike turnkey apps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$No official managed or hosted version for non-technical users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Smaller ecosystem and support base than commercial podcast apps$q$, 2);
