INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Is Pinepods free?$q$, $q$Yes, it is fully free and open source with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Do I need to host Pinepods myself?$q$, $q$Yes, it is self-hosted software; there is no official hosted SaaS version.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$What is Pinepods built with?$q$, $q$It is written primarily in Rust, with PostgreSQL or MySQL/MariaDB used for storage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Can multiple people use one Pinepods server?$q$, $q$Yes, it supports multiple user accounts with separate libraries and settings on a single instance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Does Pinepods work with AntennaPod?$q$, $q$Yes, via its built-in gpodder-compatible sync server.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$What platforms does Pinepods support?$q$, $q$Web, Windows, Mac, Linux, Android, iOS and a command-line client called Firewood.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Is Pinepods open source?$q$, $q$Yes, it is licensed under GPL-3.0 and hosted publicly on GitHub.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Who created Pinepods?$q$, $q$Developer Collin Pendleton, known on GitHub as madeofpendletonwool.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Privacy-focused podcast listening$q$, $q$Users who want full control of their podcast data run their own server instead of using a commercial app.$q$, $q$Self-hosting and privacy-focused enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Shared household podcast server$q$, $q$Families share one Pinepods server with separate user profiles for each listener.$q$, $q$Households and families$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Homelab media stack integration$q$, $q$Homelab users replace commercial podcast apps with a self-hosted tool alongside their other self-hosted services.$q$, $q$Homelab and self-hosted community$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$Self-Hosted$q$, $q$Free$q$, $q$one-time setup, no recurring fee$q$, NULL, $q$["Full feature set","Unlimited users limited only by your own server","Community support via GitHub and Discord"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pinepods is a self-hosted alternative to commercial podcast apps, built for people who want to keep their listening data on their own server instead of a third-party company's cloud. It is developed as an open-source project by Collin Pendleton and distributed under the GPL-3.0 license, with the source code hosted publicly on GitHub.$q$, $q$Because it is self-hosted, running Pinepods requires setting up a server, typically via Docker Compose with a PostgreSQL or MySQL/MariaDB database, which makes it best suited to users with at least basic homelab or self-hosting experience rather than complete beginners.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$A single Pinepods server can host multiple user accounts, each with its own subscriptions, playback history, downloads and settings, making it a natural fit for households or small teams that want to share infrastructure without sharing a single account. Clients are available for web, Windows, Mac, Linux, Android and iOS, plus a command-line client called Firewood.$q$, $q$Pinepods includes a built-in gpodder-compatible sync server so it can interoperate with other open-source podcast apps like AntennaPod, supports search across the Podcast Index, iTunes and YouTube, and adds security features like OIDC/SSO and TOTP multi-factor authentication that are important for anything exposed to the internet.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pinepods itself is completely free and open source, with no license fees, subscription tiers or paid feature gates. The only cost users incur is for whatever server or hosting infrastructure they choose to run it on, whether that is a home server, a small VPS or a NAS device.$q$, $q$Because there is no commercial entity behind Pinepods selling a hosted plan, support is community-driven through GitHub and community channels like Discord rather than a paid support contract.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('85c3b235-223c-45ae-bc99-db8243a2c741', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
