INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$Is Pingboard still an independent company?$q$, $q$No, it was acquired by Workleap in December 2023 and is now sold as Workleap Pingboard.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$How much does Pingboard cost?$q$, $q$Plans start around $4 per user per month when billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$Does Pingboard integrate with payroll or HRIS systems?$q$, $q$Yes, it syncs employee data with common HRIS and payroll platforms.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$What is Pingboard used for?$q$, $q$Building automated org charts, an employee directory, and onboarding workflows for new hires.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$Who founded Pingboard?$q$, $q$It was founded in 2013 as a standalone HR technology company in Texas before its 2023 acquisition by Workleap.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$Is there a free trial of Pingboard?$q$, $q$Yes, Workleap offers a free trial of Pingboard.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$What company size is Pingboard best for?$q$, $q$Small to mid-sized businesses; organizations above roughly 250 employees need custom pricing.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$What is the difference between Pingboard and a full HRIS?$q$, $q$Pingboard focuses on org charts, directory and onboarding, not payroll or benefits administration.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$Visualizing company structure$q$, $q$HR teams give employees a clear, always-current view of reporting lines and teams.$q$, $q$HR and people operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$New hire onboarding$q$, $q$New employees use a self-serve directory to learn who's who and how teams are organized.$q$, $q$New hires and their managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$Scaling org charts accurately$q$, $q$Fast-growing companies keep org charts accurate automatically instead of manually updating slides.$q$, $q$Scaling startups and mid-sized companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$Pingboard$q$, $q$$4/user/month billed annually ($5/user/month billed monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Automated org charts","Employee directory","Onboarding tools","HRIS integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$Enterprise (250+ employees)$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Custom deployment","Added security and admin controls","Dedicated support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pingboard started in 2013 as a standalone HR technology company focused on solving a very specific problem: keeping org charts and employee directories accurate as companies grow and change. Rather than a manually drawn chart in PowerPoint or Visio, Pingboard builds charts that update automatically as employee data changes.$q$, $q$In December 2023 the product was acquired by Workleap, a Montreal-based employee experience software company, and is now marketed as Workleap Pingboard, sold alongside Workleap's other people-management and engagement tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pingboard's core feature is its automated org chart, which reflects reporting lines, teams and roles as they change without manual redrawing, paired with a searchable employee directory that includes profiles, contact details and custom fields. Onboarding workflows and checklists help new hires quickly understand who's who and how the company is structured.$q$, $q$Pingboard integrates with common HRIS and payroll systems to keep employee data synced automatically, and includes a mobile app so employees can look up colleagues and org structure on the go.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3e8b9691-f4ea-48a6-bf97-0daae2c823ac', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pingboard is priced per user per month, starting at roughly 4 dollars per user per month when billed annually, or around 5 dollars per user per month on monthly billing. Workleap's modular pricing approach lets customers combine Pingboard with other Workleap products under one contract.$q$, $q$Organizations with more than roughly 250 employees are directed to contact Workleap's sales team for custom enterprise pricing that reflects their size, feature needs and support requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Synthetic uptime monitoring$q$, $q$Simulated checks from global locations detect downtime and slow response times.$q$, 0);
