INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Who owns Pingdom?$q$, $q$SolarWinds, which acquired Pingdom in 2014 for approximately $103 million.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$What does Pingdom monitor?$q$, $q$Website uptime, page speed, multi-step transactions and real user performance.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$How much does Pingdom cost?$q$, $q$Plans start around $15/month for the Starter tier, up to around $249/month for Professional.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$What is the difference between synthetic and real user monitoring in Pingdom?$q$, $q$Synthetic monitoring runs simulated checks from global locations, while RUM captures data from real visitors.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Does Pingdom offer status pages?$q$, $q$Yes, public status pages are included to communicate incidents to customers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$When was Pingdom founded?$q$, $q$It launched in 2005 in Sweden, before being acquired by SolarWinds in 2014.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$What are Pingdom's main competitors?$q$, $q$UptimeRobot, StatusCake, Site24x7, Datadog Synthetic Monitoring and New Relic.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Does Pingdom have a free trial?$q$, $q$Yes, a 14-day free trial including Synthetics and Real User Monitoring is available.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Production website monitoring$q$, $q$DevOps and SRE teams monitor uptime and performance of live websites and APIs.$q$, $q$DevOps and SRE teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Multi-client monitoring for agencies$q$, $q$Agencies monitor multiple client websites from a single dashboard.$q$, $q$Digital agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$E-commerce checkout monitoring$q$, $q$E-commerce teams monitor checkout flows and page speed to protect conversion rates.$q$, $q$E-commerce and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Starter$q$, $q$$15/month$q$, $q$monthly$q$, NULL, $q$["10 uptime monitors","1 advanced monitor","50 SMS alerts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Standard$q$, $q$$50/month$q$, $q$monthly$q$, NULL, $q$["50 uptime monitors","5 advanced monitors"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Advanced$q$, $q$$95/month$q$, $q$monthly$q$, NULL, $q$["100 uptime monitors","10 advanced monitors"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Professional$q$, $q$$249/month$q$, $q$monthly$q$, NULL, $q$["Highest monitor limits for agencies and enterprise teams"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$Real User Monitoring (RUM)$q$, $q$from $10/month$q$, $q$monthly$q$, NULL, $q$["Real visitor performance data including Core Web Vitals"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pingdom is one of the longest-running website monitoring services on the market, launched in Sweden in 2005 and acquired by SolarWinds in 2014. It built its reputation on a simple premise: periodically check websites from locations around the world and alert teams the moment something breaks.$q$, $q$As part of SolarWinds, Pingdom now sits alongside a broader family of observability and IT management products, but it has retained a simple, developer-friendly interface that appeals to smaller teams who do not need a full enterprise observability platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pingdom's synthetic monitoring simulates visits to websites, APIs and multi-step transactions such as checkout flows from global locations, flagging downtime, slow response times, SSL certificate problems and broken user journeys. Real User Monitoring complements this by capturing actual visitor performance data, including Core Web Vitals, from real traffic.$q$, $q$Teams are alerted through email, SMS, Slack and other integrations, and can publish public status pages to keep customers informed during incidents, a feature widely used by SaaS companies to manage outage communication transparently.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0f7793fe-24f6-455d-942f-7c400a00d262', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pingdom's core synthetic monitoring plans scale by the number of uptime and advanced (transaction) monitors included: Starter at roughly 15 dollars per month, Standard at roughly 50 dollars per month, Advanced at roughly 95 dollars per month, and Professional at roughly 249 dollars per month for agencies and larger portfolios.$q$, $q$Real User Monitoring is sold as a separate add-on plan starting around 10 dollars per month, and Pingdom offers a 14-day free trial that includes both synthetic monitoring and RUM so teams can evaluate the full feature set before committing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Career site builder$q$, $q$Drag-and-drop, SEO-optimized career pages with no code required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Applicant tracking core$q$, $q$Pipeline management, structured scorecards and collaborative candidate evaluation.$q$, 1);
