INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Less brand recognition in the US market compared to larger competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$May be less feature-rich than Greenhouse for very large, complex enterprise hiring operations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Best suited to mid-market teams; may be over- or under-featured at the extremes of company size$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Is Pinpoint the same as AWS Pinpoint?$q$, $q$No, this Pinpoint (pinpointhq.com) is a separate applicant tracking system and is unrelated to Amazon's messaging service or Atlassian's product of the same name.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$What is Pinpoint used for?$q$, $q$Managing job postings, candidate pipelines, interviews and employer branding for in-house recruiting teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$How much does Pinpoint cost?$q$, $q$Pricing is custom and quote-based; Pinpoint does not publish fixed prices.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Who founded Pinpoint?$q$, $q$Pinpoint was founded in 2017 and is headquartered in the United Kingdom.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$What company size is Pinpoint best for?$q$, $q$Primarily mid-market organizations, commonly cited as roughly 200 to 2,000 employees.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$How does Pinpoint compare to Greenhouse?$q$, $q$Pinpoint offers stronger built-in employer branding tools and faster setup, while Greenhouse has a larger enterprise integration ecosystem.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Is Pinpoint GDPR compliant?$q$, $q$Yes, it is built with GDPR-native data handling aimed at UK and EU customers.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Does Pinpoint include a career site builder?$q$, $q$Yes, a drag-and-drop, SEO-optimized career site builder is included.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Centralized in-house hiring$q$, $q$In-house talent acquisition teams centralize career sites, applications and hiring workflow in one platform.$q$, $q$Talent acquisition and recruiting teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$GDPR-compliant hiring in Europe$q$, $q$UK and EU companies use Pinpoint's GDPR-native data handling for compliant applicant tracking.$q$, $q$European employers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Scaling mid-market hiring$q$, $q$Mid-market companies scale hiring volume without heavy IT or HR operations overhead.$q$, $q$Mid-market HR and recruiting leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$Custom$q$, $q$Custom (contact sales)$q$, $q$annual$q$, NULL, $q$["Career site builder","Full applicant tracking system","Interview scheduling automation","Offer management","Reporting and analytics","GDPR-native data handling"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Pinpoint was founded in 2017 in the United Kingdom to serve a specific gap in the applicant tracking market: in-house talent acquisition teams that wanted employer branding and candidate experience tools built into their ATS rather than bolted on separately. Note that this Pinpoint, at pinpointhq.com, is unrelated to Amazon's AWS Pinpoint messaging service or Atlassian's similarly named product.$q$, $q$The platform is aimed primarily at mid-market organizations, commonly cited as roughly 200 to 2,000 employees, that need a single system covering career sites, applications, interviews and offers rather than juggling separate recruitment marketing and ATS tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pinpoint's career site builder lets recruiting teams create SEO-optimized, branded career pages without developer involvement, feeding directly into an ATS core that manages pipeline stages, structured interview scorecards and collaborative candidate evaluation.$q$, $q$Automation features handle much of the administrative burden of hiring, including interview scheduling coordination, personalized candidate communication sequences, and offer management, while built-in reporting tracks hiring funnel metrics for recruiting leaders.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1850649f-0915-4e09-87b7-b7aa588ddd00', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pinpoint does not publish fixed pricing; instead, prospective customers request a custom quote based on hiring volume, team size and required features through the company's sales team.$q$, $q$Third-party pricing estimates suggest costs can range from several hundred dollars per month for smaller growth-tier plans up to roughly 1,200 dollars per month or more for enterprise-level deployments, though these figures are third-party estimates rather than figures published by Pinpoint itself.$q$]::text[], 2);
